import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"平台功能: 多平台额度查询支持 | opencode-mystatus","description":"学习 opencode-mystatus 支持的 4 个主流 AI 平台额度查询方法。涵盖 OpenAI、智谱 AI、GitHub Copilot 和 Google Cloud 平台，详细说明各平台的限额计算方式和特点。","frontmatter":{"title":"平台功能: 多平台额度查询支持 | opencode-mystatus","sidebarTitle":"平台功能","subtitle":"平台功能: 多平台额度查询支持","description":"学习 opencode-mystatus 支持的 4 个主流 AI 平台额度查询方法。涵盖 OpenAI、智谱 AI、GitHub Copilot 和 Google Cloud 平台，详细说明各平台的限额计算方式和特点。","order":2},"headers":[],"relativePath":"zh/vbgate/opencode-mystatus/platforms/index.md","filePath":"zh/vbgate/opencode-mystatus/platforms/index.md"}'),i={name:"zh/vbgate/opencode-mystatus/platforms/index.md"};function r(d,a,n,s,u,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章节详细介绍 opencode-mystatus 支持的各个 AI 平台的额度查询功能。</p><h2 id="支持的平台" tabindex="-1">支持的平台 <a class="header-anchor" href="#支持的平台" aria-label="Permalink to &quot;支持的平台&quot;">​</a></h2><p>opencode-mystatus 支持以下 4 个主流 AI 平台：</p><table tabindex="0"><thead><tr><th>平台</th><th>限额类型</th><th>特点</th></tr></thead><tbody><tr><td>OpenAI</td><td>3 小时 / 24 小时滑动窗口</td><td>支持 Plus、Team、Pro 订阅</td></tr><tr><td>智谱 AI</td><td>5 小时 Token / MCP 月度配额</td><td>支持 Coding Plan</td></tr><tr><td>GitHub Copilot</td><td>月度配额</td><td>显示 Premium Requests 使用量</td></tr><tr><td>Google Cloud</td><td>按模型独立计算</td><td>支持多账号、4 个模型</td></tr></tbody></table><h2 id="平台详解" tabindex="-1">平台详解 <a class="header-anchor" href="#平台详解" aria-label="Permalink to &quot;平台详解&quot;">​</a></h2><h3 id="openai-额度" tabindex="-1"><a href="./openai-usage/">OpenAI 额度</a> <a class="header-anchor" href="#openai-额度" aria-label="Permalink to &quot;[OpenAI 额度](./openai-usage/)&quot;">​</a></h3><p>深入了解 OpenAI 的额度查询机制：</p><ul><li>3 小时和 24 小时滑动窗口的区别</li><li>Team 账号的额度共享机制</li><li>JWT Token 解析获取账号信息</li></ul><h3 id="智谱-ai-额度" tabindex="-1"><a href="./zhipu-usage/">智谱 AI 额度</a> <a class="header-anchor" href="#智谱-ai-额度" aria-label="Permalink to &quot;[智谱 AI 额度](./zhipu-usage/)&quot;">​</a></h3><p>了解智谱 AI 和 Z.ai 的额度查询：</p><ul><li>5 小时 Token 限额的计算方式</li><li>MCP 月度配额的用途</li><li>API Key 脱敏显示</li></ul><h3 id="github-copilot-额度" tabindex="-1"><a href="./copilot-usage/">GitHub Copilot 额度</a> <a class="header-anchor" href="#github-copilot-额度" aria-label="Permalink to &quot;[GitHub Copilot 额度](./copilot-usage/)&quot;">​</a></h3><p>掌握 GitHub Copilot 的额度管理：</p><ul><li>Premium Requests 的含义</li><li>不同订阅类型的配额差异</li><li>月度重置时间计算</li></ul><h3 id="google-cloud-额度" tabindex="-1"><a href="./google-usage/">Google Cloud 额度</a> <a class="header-anchor" href="#google-cloud-额度" aria-label="Permalink to &quot;[Google Cloud 额度](./google-usage/)&quot;">​</a></h3><p>学习 Google Cloud 多账号额度查询：</p><ul><li>4 个模型（G3 Pro、G3 Image、G3 Flash、Claude）的区别</li><li>多账号管理和切换</li><li>认证文件读取机制</li></ul><h2 id="选择指南" tabindex="-1">选择指南 <a class="header-anchor" href="#选择指南" aria-label="Permalink to &quot;选择指南&quot;">​</a></h2><p>根据你使用的平台，选择对应的教程：</p><ul><li><strong>只用 OpenAI</strong>：直接看 <a href="./openai-usage/">OpenAI 额度</a></li><li><strong>只用智谱 AI</strong>：直接看 <a href="./zhipu-usage/">智谱 AI 额度</a></li><li><strong>多平台用户</strong>：建议按顺序阅读所有平台教程</li><li><strong>Google Cloud 用户</strong>：需要先安装 <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> 插件</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章节后，可以继续学习 <a href="./../advanced/">高级功能</a>，了解更多配置选项。</p>',23)])])}const g=e(i,[["render",r]]);export{c as __pageData,g as default};
